import fs from 'node:fs';
import path from 'node:path';
import dotenv from 'dotenv';

const dir = process.cwd();
const files = ['.env.local', '.env.test'];
const parsed = Object.fromEntries(files.map((file) => {
  const full = path.join(dir, file);
  return [file, dotenv.parse(fs.readFileSync(full, 'utf8'))];
}));

const keys = Array.from(new Set(files.flatMap((file) => Object.keys(parsed[file])))).sort();
console.log('Env key comparison (values masked):');
for (const key of keys) {
  const local = parsed['.env.local'][key];
  const test = parsed['.env.test'][key];
  const same = local !== undefined && test !== undefined && local === test;
  const localInfo = local === undefined ? 'missing' : `present len=${local.length}`;
  const testInfo = test === undefined ? 'missing' : `present len=${test.length}`;
  console.log(`- ${key}: local ${localInfo}; test ${testInfo}; same=${same}`);
}

function parseJson(raw) {
  if (!raw) return null;
  try { return JSON.parse(raw); } catch {}
  try {
    const parsedOnce = JSON.parse(raw);
    if (typeof parsedOnce === 'string') return JSON.parse(parsedOnce);
  } catch {}
  return null;
}

for (const file of files) {
  const env = parsed[file];
  const apps = parseJson(env.AUTH_APPS);
  console.log(`\n${file} AUTH_APPS summary:`);
  if (!apps || typeof apps !== 'object' || Array.isArray(apps)) {
    console.log('- invalid or missing AUTH_APPS');
    continue;
  }
  for (const [slug, entry] of Object.entries(apps)) {
    const sessionSecretEnv = entry?.sessionSecretEnv;
    const inlineSecret = typeof entry?.sessionSecret === 'string';
    const referenced = typeof sessionSecretEnv === 'string' ? env[sessionSecretEnv] : undefined;
    console.log(`- ${slug}: sessionSecretEnv=${sessionSecretEnv ?? 'none'}; referenced=${referenced ? `present len=${referenced.length}` : 'missing'}; inlineSecret=${inlineSecret}; allowedOrigins=${JSON.stringify(entry?.allowedOrigins ?? [])}; cookieDomain=${JSON.stringify(entry?.cookieDomain ?? '')}`);
  }
  if (env.TEST_APP_SECRET) {
    console.log(`- TEST_APP_SECRET present len=${env.TEST_APP_SECRET.length}`);
    if (apps['test-app']) {
      const ref = apps['test-app'].sessionSecretEnv;
      const refValue = typeof ref === 'string' ? env[ref] : undefined;
      console.log(`- test-app secret matches TEST_APP_SECRET=${Boolean(refValue && refValue === env.TEST_APP_SECRET)}`);
    }
  }
}
